import React, { useState, useEffect } from 'react';
import { supabase } from './supabase';

// Obtener negocio_id de la URL: ?negocio=UUID
function getNegocioId() {
  const params = new URLSearchParams(window.location.search);
  return params.get('negocio');
}

export default function App() {
  const [negocio, setNegocio] = useState(null);
  const [productos, setProductos] = useState([]);
  const [carrito, setCarrito] = useState([]);
  const [pantalla, setPantalla] = useState('catalogo'); // catalogo | carrito | datos | confirmado
  const [cargando, setCargando] = useState(true);
  const [enviando, setEnviando] = useState(false);
  const [error, setError] = useState('');
  const [form, setForm] = useState({ nombre:'', telefono:'', direccion:'', nota:'' });
  const negocioId = getNegocioId();

  useEffect(() => {
    if (!negocioId) { setCargando(false); return; }
    const cargar = async () => {
      const { data: neg } = await supabase.from('negocios').select('*').eq('id', negocioId).single();
      const { data: prods } = await supabase.from('productos').select('*').eq('negocio_id', negocioId).eq('activo', true);
      setNegocio(neg);
      setProductos(prods || []);
      setCargando(false);
    };
    cargar();
  }, [negocioId]);

  const agregarAlCarrito = (prod) => {
    setCarrito(prev => {
      const existe = prev.find(x => x.id === prod.id);
      if (existe) return prev.map(x => x.id===prod.id ? {...x, cant: x.cant+1} : x);
      return [...prev, { ...prod, cant: 1 }];
    });
  };

  const cambiarCant = (id, delta) => {
    setCarrito(prev => {
      const actualizado = prev.map(x => x.id===id ? {...x, cant: x.cant+delta} : x).filter(x => x.cant > 0);
      return actualizado;
    });
  };

  const total = carrito.reduce((s,x) => s + x.cant*x.precio, 0);
  const delivery = 15;
  const totalFinal = total + delivery;
  const cantTotal = carrito.reduce((s,x) => s + x.cant, 0);

  const confirmarPedido = async () => {
    if (!form.nombre || !form.telefono || !form.direccion) { setError('Por favor llena todos los campos'); return; }
    setEnviando(true); setError('');
    const { error } = await supabase.from('pedidos').insert({
      negocio_id: negocioId,
      cliente_nombre: form.nombre,
      cliente_telefono: form.telefono,
      cliente_direccion: form.direccion,
      productos: carrito.map(x => ({ nombre: x.nombre, cant: x.cant, precio: x.precio })),
      total: totalFinal,
      estado: 'nuevo',
      nota: form.nota
    });
    if (error) { setError('Error al enviar el pedido. Intenta de nuevo.'); setEnviando(false); return; }
    setEnviando(false);
    setPantalla('confirmado');
  };

  // Sin negocio en URL
  if (!negocioId) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:12 }}>
      <div style={{ fontSize:48 }}>🛍</div>
      <div style={{ fontSize:18, fontWeight:700 }}>PedidosFácil</div>
      <div style={{ fontSize:14, color:'#94A3B8', textAlign:'center', maxWidth:300 }}>Accede al link que te compartió el negocio para hacer tu pedido.</div>
    </div>
  );

  if (cargando) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:12 }}>
      <div style={{ fontSize:36 }}>🛍</div>
      <div style={{ fontSize:14, color:'#64748B' }}>Cargando...</div>
    </div>
  );

  if (!negocio) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:12 }}>
      <div style={{ fontSize:48 }}>😕</div>
      <div style={{ fontSize:16, fontWeight:600 }}>Negocio no encontrado</div>
      <div style={{ fontSize:14, color:'#94A3B8' }}>El link que usaste no es válido.</div>
    </div>
  );

  // PEDIDO CONFIRMADO
  if (pantalla === 'confirmado') return (
    <div style={{ minHeight:'100vh', background:'#F0FDF4', display:'flex', alignItems:'center', justifyContent:'center', padding:'1rem' }}>
      <div style={{ background:'#fff', borderRadius:20, padding:'2.5rem', textAlign:'center', maxWidth:380, width:'100%', boxShadow:'0 4px 24px rgba(0,0,0,0.08)' }}>
        <div style={{ fontSize:64, marginBottom:16 }}>✅</div>
        <div style={{ fontSize:22, fontWeight:700, marginBottom:8 }}>¡Pedido enviado!</div>
        <div style={{ fontSize:15, color:'#64748B', marginBottom:24 }}>
          Tu pedido fue recibido por <strong>{negocio.nombre}</strong>. Pronto te contactarán al número <strong>{form.telefono}</strong>.
        </div>
        <div style={{ background:'#F0FDF4', borderRadius:12, padding:'1rem', marginBottom:24, textAlign:'left' }}>
          <div style={{ fontSize:13, color:'#64748B', marginBottom:8 }}>Resumen:</div>
          {carrito.map((x,i) => (
            <div key={i} style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:4 }}>
              <span>{x.cant}x {x.nombre}</span>
              <span>Bs. {x.cant*x.precio}</span>
            </div>
          ))}
          <div style={{ borderTop:'1px solid #D1FAE5', marginTop:8, paddingTop:8, display:'flex', justifyContent:'space-between', fontWeight:700 }}>
            <span>Total</span><span>Bs. {totalFinal}</span>
          </div>
        </div>
        <button onClick={()=>{ setCarrito([]); setForm({nombre:'',telefono:'',direccion:'',nota:''}); setPantalla('catalogo'); }}
          style={{ width:'100%', padding:'12px', borderRadius:10, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, fontSize:15, cursor:'pointer' }}>
          Hacer otro pedido
        </button>
      </div>
    </div>
  );

  return (
    <div style={{ maxWidth:480, margin:'0 auto', minHeight:'100vh', background:'#fff', position:'relative' }}>
      {/* Header */}
      <div style={{ background:'#2563EB', color:'#fff', padding:'1.25rem 1rem', position:'sticky', top:0, zIndex:10 }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
          <div>
            <div style={{ fontWeight:700, fontSize:18 }}>{negocio.nombre}</div>
            <div style={{ fontSize:12, opacity:0.8 }}>{negocio.tipo} · Pedidos online</div>
          </div>
          {pantalla==='catalogo' && carrito.length > 0 && (
            <button onClick={()=>setPantalla('carrito')}
              style={{ background:'#fff', color:'#2563EB', border:'none', borderRadius:99, padding:'8px 16px', fontWeight:700, cursor:'pointer', fontSize:14, display:'flex', alignItems:'center', gap:6 }}>
              🛒 {cantTotal} · Bs. {total}
            </button>
          )}
          {pantalla !== 'catalogo' && (
            <button onClick={()=>setPantalla(pantalla==='datos'?'carrito':'catalogo')}
              style={{ background:'rgba(255,255,255,0.2)', color:'#fff', border:'none', borderRadius:8, padding:'6px 12px', cursor:'pointer', fontSize:14 }}>
              ← Volver
            </button>
          )}
        </div>
        {/* Pasos */}
        {pantalla !== 'catalogo' && (
          <div style={{ display:'flex', gap:4, marginTop:12 }}>
            {['carrito','datos'].map((paso,i) => (
              <div key={paso} style={{ flex:1, height:3, borderRadius:99, background: pantalla===paso||( paso==='carrito'&&pantalla==='datos') ? '#fff' : 'rgba(255,255,255,0.3)' }} />
            ))}
          </div>
        )}
      </div>

      {/* CATÁLOGO */}
      {pantalla==='catalogo' && (
        <div style={{ padding:'1rem' }}>
          {productos.length === 0 ? (
            <div style={{ textAlign:'center', padding:'3rem', color:'#94A3B8' }}>
              <div style={{ fontSize:40, marginBottom:12 }}>😔</div>
              <div style={{ fontWeight:600 }}>No hay productos disponibles</div>
              <div style={{ fontSize:14, marginTop:4 }}>El negocio aún no ha agregado productos.</div>
            </div>
          ) : (
            <>
              <div style={{ fontSize:14, color:'#64748B', marginBottom:'1rem' }}>
                {productos.length} productos disponibles
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {productos.map(prod => {
                  const enCarrito = carrito.find(x=>x.id===prod.id);
                  return (
                    <div key={prod.id} style={{ display:'flex', alignItems:'center', gap:12, background:'#F8FAFC', borderRadius:14, padding:'12px 14px' }}>
                      <div style={{ fontSize:36, flexShrink:0 }}>{prod.emoji||'📦'}</div>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:600, fontSize:15 }}>{prod.nombre}</div>
                        <div style={{ fontSize:13, color:'#64748B' }}>{prod.categoria}</div>
                        <div style={{ fontWeight:700, color:'#2563EB', fontSize:15, marginTop:2 }}>Bs. {prod.precio}</div>
                      </div>
                      {enCarrito ? (
                        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                          <button onClick={()=>cambiarCant(prod.id,-1)}
                            style={{ width:32, height:32, borderRadius:'50%', border:'2px solid #2563EB', background:'#fff', color:'#2563EB', fontSize:18, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700 }}>−</button>
                          <span style={{ fontWeight:700, fontSize:16, minWidth:20, textAlign:'center' }}>{enCarrito.cant}</span>
                          <button onClick={()=>cambiarCant(prod.id,1)}
                            style={{ width:32, height:32, borderRadius:'50%', border:'none', background:'#2563EB', color:'#fff', fontSize:18, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700 }}>+</button>
                        </div>
                      ) : (
                        <button onClick={()=>agregarAlCarrito(prod)}
                          style={{ padding:'8px 16px', borderRadius:99, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, cursor:'pointer', fontSize:13 }}>
                          + Agregar
                        </button>
                      )}
                    </div>
                  );
                })}
              </div>
            </>
          )}

          {carrito.length > 0 && (
            <div style={{ position:'sticky', bottom:0, background:'#fff', padding:'1rem 0', marginTop:'1rem' }}>
              <button onClick={()=>setPantalla('carrito')}
                style={{ width:'100%', padding:'14px', borderRadius:12, border:'none', background:'#2563EB', color:'#fff', fontWeight:700, fontSize:16, cursor:'pointer' }}>
                Ver carrito · {cantTotal} productos · Bs. {total}
              </button>
            </div>
          )}
        </div>
      )}

      {/* CARRITO */}
      {pantalla==='carrito' && (
        <div style={{ padding:'1rem' }}>
          <div style={{ fontWeight:700, fontSize:16, marginBottom:'1rem' }}>Tu carrito</div>
          <div style={{ display:'flex', flexDirection:'column', gap:10, marginBottom:'1rem' }}>
            {carrito.map(x => (
              <div key={x.id} style={{ display:'flex', alignItems:'center', gap:12, background:'#F8FAFC', borderRadius:14, padding:'12px 14px' }}>
                <div style={{ fontSize:28 }}>{x.emoji||'📦'}</div>
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:600, fontSize:14 }}>{x.nombre}</div>
                  <div style={{ fontSize:13, color:'#2563EB', fontWeight:600 }}>Bs. {x.precio} c/u</div>
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                  <button onClick={()=>cambiarCant(x.id,-1)}
                    style={{ width:28, height:28, borderRadius:'50%', border:'2px solid #E2E8F0', background:'#fff', fontSize:16, cursor:'pointer', fontWeight:700 }}>−</button>
                  <span style={{ fontWeight:700, fontSize:15, minWidth:18, textAlign:'center' }}>{x.cant}</span>
                  <button onClick={()=>cambiarCant(x.id,1)}
                    style={{ width:28, height:28, borderRadius:'50%', border:'none', background:'#2563EB', color:'#fff', fontSize:16, cursor:'pointer', fontWeight:700 }}>+</button>
                </div>
                <div style={{ fontWeight:700, fontSize:14, minWidth:60, textAlign:'right' }}>Bs. {x.cant*x.precio}</div>
              </div>
            ))}
          </div>

          <div style={{ background:'#F8FAFC', borderRadius:14, padding:'1rem', marginBottom:'1rem' }}>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:6, color:'#64748B' }}>
              <span>Subtotal</span><span>Bs. {total}</span>
            </div>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:10, color:'#64748B' }}>
              <span>Delivery</span><span>Bs. {delivery}</span>
            </div>
            <div style={{ display:'flex', justifyContent:'space-between', fontWeight:700, fontSize:16, borderTop:'1px solid #E2E8F0', paddingTop:10 }}>
              <span>Total</span><span style={{ color:'#2563EB' }}>Bs. {totalFinal}</span>
            </div>
          </div>

          <button onClick={()=>setPantalla('datos')}
            style={{ width:'100%', padding:'14px', borderRadius:12, border:'none', background:'#2563EB', color:'#fff', fontWeight:700, fontSize:16, cursor:'pointer' }}>
            Continuar → Mis datos
          </button>
        </div>
      )}

      {/* DATOS DEL CLIENTE */}
      {pantalla==='datos' && (
        <div style={{ padding:'1rem' }}>
          <div style={{ fontWeight:700, fontSize:16, marginBottom:6 }}>¿A dónde enviamos tu pedido?</div>
          <div style={{ fontSize:14, color:'#94A3B8', marginBottom:'1.25rem' }}>Total a pagar: <strong style={{ color:'#2563EB' }}>Bs. {totalFinal}</strong></div>

          {['nombre','telefono','direccion'].map(campo => (
            <div key={campo} style={{ marginBottom:'0.75rem' }}>
              <label style={{ fontSize:13, color:'#64748B', display:'block', marginBottom:4 }}>
                {campo==='nombre'?'Tu nombre completo':campo==='telefono'?'Teléfono / WhatsApp':'Dirección de entrega'}
                <span style={{ color:'#EF4444' }}> *</span>
              </label>
              <input value={form[campo]} onChange={e=>setForm({...form,[campo]:e.target.value})}
                placeholder={campo==='nombre'?'Ej: Juan Pérez':campo==='telefono'?'Ej: 71234567':'Ej: Av. Montes 345, piso 2'}
                style={{ width:'100%', padding:'12px', borderRadius:10, border:'1px solid #E2E8F0', fontSize:15, outline:'none' }} />
            </div>
          ))}

          <div style={{ marginBottom:'1.25rem' }}>
            <label style={{ fontSize:13, color:'#64748B', display:'block', marginBottom:4 }}>Nota para el negocio (opcional)</label>
            <textarea value={form.nota} onChange={e=>setForm({...form,nota:e.target.value})}
              placeholder="Ej: Sin cebolla, tocar el timbre..."
              rows={3}
              style={{ width:'100%', padding:'12px', borderRadius:10, border:'1px solid #E2E8F0', fontSize:14, outline:'none', resize:'none' }} />
          </div>

          {error && (
            <div style={{ background:'#FEF2F2', color:'#DC2626', padding:'10px 12px', borderRadius:8, fontSize:14, marginBottom:'1rem' }}>
              {error}
            </div>
          )}

          <button onClick={confirmarPedido} disabled={enviando}
            style={{ width:'100%', padding:'14px', borderRadius:12, border:'none', background: enviando?'#93C5FD':'#2563EB', color:'#fff', fontWeight:700, fontSize:16, cursor: enviando?'not-allowed':'pointer' }}>
            {enviando ? 'Enviando pedido...' : `✅ Confirmar pedido · Bs. ${totalFinal}`}
          </button>

          <div style={{ textAlign:'center', fontSize:12, color:'#94A3B8', marginTop:'1rem' }}>
            Al confirmar, el negocio recibirá tu pedido inmediatamente
          </div>
        </div>
      )}
    </div>
  );
}
